script.text:

function active$FormManagerLevel(f) {f.add_onResponseComplete(on$FormManagerLevel$ResponseComplete);}
function close$FormManagerLevel(f) {try {f.remove_onResponseComplete(on$FormManagerLevel$ResponseComplete)} catch (ex) {}}
function on$FormManagerLevel$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_bac');
      break;
    default:
      break;
  }
}

      &ScriptIrregular;
